mapper.select:
SELECT recruit_no AS recruitNo, writer_no AS writerNo, title, department, career, recruit_type AS recruitType,
       start_date AS startDate, end_date AS endDate, note, status, reg_date AS regDate
FROM recruit WHERE recruit_no=#{recruitNo}

mapper.update:
UPDATE recruit SET writer_no=#{writerNo}, title=#{title}, department=#{department}, career=#{career}, recruit_type=#{recruitType},
    start_date=#{startDate}, end_date=#{endDate}, note=#{note}, status=#{status}
WHERE recruit_no=#{recruitNo}
